dat.pdc = read_csv("pdc2024.csv")
dat.pdc = tibble(dat.pdc) |&gt;
  filter(Score != "w/o") |&gt;
  filter(Night !=  "Finals") |&gt;
  mutate(Matchnum = row_number()) |&gt;
  separate(Score, into = c("WinnerLegs", "LoserLegs"), sep = "-", convert = TRUE)






