Code
dat.pdc = dat.pdc |&gt; mutate(MatchID = row_number())

cum_legs = function(player) {
  dat.pdc |&gt;
    filter(Winner == player | Loser == player) |&gt;
    mutate(
      LegsWon = case_when(
        Winner == player ~ WinnerLegs,
        Loser  == player ~ LoserLegs
      ),
      CumLegsWon = cumsum(LegsWon)
    ) |&gt;
    select(MatchID, CumLegsWon) |&gt;
    rename(!!player := CumLegsWon)
}

players = unique(as.character(c(dat.pdc$Winner, dat.pdc$Loser)))

cum_data = map(players, cum_legs) |&gt; reduce(full_join, by = "MatchID")

dat.pdc = dat.pdc |&gt; left_join(cum_data, by = "MatchID")

dat.pdc = dat.pdc |&gt;
  fill(any_of(players), .direction = "down") |&gt;
  mutate(across(any_of(players), ~ replace_na(., 0)))






